IMAGOdb.zones[2405].name = "Voidstorm"
IMAGOdb.zones[2405].lore = "Not much is known about the scarred landscape now known as the Voidstorm. Hostile and alien, this broken world once knew life and peace. In times past, the hills and crags were part of a world called Predacea. A society of knowledge and scientific progress, Predacea was not immune to the drums of war. In seeking an end to all conflict, a weapon of mass destruction was unleashed that ended their civilization entirely. Untold years later, the remnants of this planet have become the staging ground for Xal’atath’s war on Azeroth."
IMAGOdb.zones[2405].pointsOfInterest = {
    {
        name = "Slayer's Rise",
        lore = "The stench of fresh blood fills the air across the plains of Slayer’s Rise. Two domanaar, Vidious and Ziadan, wage war on one another. Ostensibly, the two battle for control of the territory, but the glee each seems to take in the bloodshed certainly plays a role in their schemes. The two foes have recruited equally bloodthirsty members of the Horde and Alliance, sending them to battle in their names for glory… or for sport."
    },
    {
        name = "Stormarion Citadel",
        lore = "Stormarion Citadel rests on the southwest edge of the Voidstorm, peering out over an endless expanse of jagged canyons and dead earth. An outfit of ren’dorei researchers now occupy the area, attempting to stabilize the multitude of singularities scattered around the citadel. Threatened on all sides by the Xal’atath’s forces, these brave void elves continue their work no matter the cost."
    },
    {
        name = "Voidspire",
        lore = "Xal’atath’s grand design brought to fruition, the Voidspire looms over the entirety of the Voidstorm. Created with the captured essence of Dimensius the All-Devouring, the Voidspire is a focus of dark energy unlike any Azeroth has ever seen. Here, the Devouring Host marshals their forces in preparation for their inevitable final assault on Quel’Thalas"
    }
}

IMAGOdb.zones[2413].name = "Harandar"
IMAGOdb.zones[2413].lore = "Harandar is the home of the haranir, concealed deep beneath the massive rootways of the world trees. This bioluminescent fungal jungle is a place of primordial magic, whose inhabitants live as secret guardians of Azeroth in perfect harmony with nature. However, the peaceful existence of the Hara'ti tribe is on the brink: The Rift of Aln, a primordial wound, blurs the line between dream and reality, spewing forth terrifying nightmares. Simultaneously, the destructive and fanatical power of the Lightbloom overgrows the land, corrupting the native flora."
IMAGOdb.zones[2413].pointsOfInterest = {
    {
        name = "The Rift of Aln",
        lore = "A primordial wound in the fabric of Azeroth. Here, the barrier to the plane of dreams is so thin that the echoes of the Goddess' anguish are powerful enough to drive even the strongest mind to madness."
    },
    {
        name = "The Blinding Vale",
        lore = "A terrifying testament to the recent threat. The Lightbloom sprouted instantly here, transforming the once-peaceful Rutaani into blind zealots under the command of the power-hungry Lightkeeper Ruia."
    },
    {
        name = "The Den of Echoes",
        lore = "The spiritual and political heart of Harandar. Here, the Elder Council gathers around Naynar to preserve the magical paintings of the ancestors and orchestrate the salvation of the rootways."
    },
}

IMAGOdb.zones[2437].name = "Zul'Aman"
IMAGOdb.zones[2437].lore = "The towering forests of Zul’Aman have been home to the Amani trolls since long before the high elves ever established Quel’Thalas. Border skirmishes have defined the relationship between the two factions for as long as anyone can remember. Under the leadership of Zul’jin, the Amani twisted the magic of their loa to violent ends. In response, the wild gods went silent, abandoning the Amani tribe to their own fate for decades. Now, with the Twilight’s Blade infesting their woods, the trolls look to their neighbors for aid. Zul’jin’s grandchildren, Zul’jarra and Zul’jan, seek to guide the Amani back to their former glory."
IMAGOdb.zones[2437].pointsOfInterest = {
    {
        name = "Amani’Zar Village",
        lore = "As the largest village in Zul’Aman and de facto capital of the Amani people, Amani’Zar Village has become a melting pot of troll culture. Many tribes fall under the Amani banner, including the Witherbark, Shadowpine, and Revantusk. Members of each of these tribes make their home in Amani’Zar, uniting their people against threats like the Viletusk and Twilight’s Blade."
    },
    {
        name = "The Loa Temples",
        lore = "Dedicated temples to each of the major Amani loa dot the landscape throughout Zul’Aman. Halazzi the lynx, Jan’alai the dragonhawk, Nalorakk the bear, and Akil’zon the eagle each had major structures built in their honor. Though they were once spiritual centers of the Amani empire, they went silent after Zul’jin’s betrayal. Under Zul’jarra, the voices of the loa have returned to their people, and their temples have reawakened."
    },
    {
        name = "Atal'Aman",
        lore = "The city of Atal'Aman was once a sacred site for the Amani. The temples built throughout were a gathering place for many disciples of the loa. Though still inhabited by the Amani, the spiritual meaning of the temple city has been all but lost. After Zul’jin betrayed the loa and stole their power for himself, the gods vanished, and their worshippers with them. The site has seen frequent bloodshed, being raided by opportunistic adventurers on two separate occasions. Even today, the spirits of those assaults run rampant across these sacred grounds."
    },
}

IMAGOdb.zones[2395].name = "Eversong Woods"
IMAGOdb.zones[2395].lore = "Eversong Woods, the golden heart of Quel'thalas and home of the blood elves. These breathtaking lands have been marred by many tragedies, most caused by the potent magic of the Sunwell tempting those who would use its power to their own nefarious ends. After Arthas carved a path of death and decay through the center of the woods, many believed the land would never recover. Over decades, however, blood elf magisters were able to cultivate life anew, returning Eversong to its former glory. Still, with the Devouring Host threatening from above and the Lightbloom bursting from below, Eversong Woods is beset by threats on all sides."
IMAGOdb.zones[2395].pointsOfInterest = {
    {
        name = "Sunstrider Isle",
        lore = "The tales of many heroic blood knights, magisters and blood elves of all stripes began somewhere. Sunstrider Isle has served as a place of learning for young sin'dorei for generations. Once abandoned, the towering Falthrien Academy now nurtures fresh minds once more, imparting the skills any adventurer will need on the path ahead of them."
    },
    {
        name = "Fairbreeze Village",
        lore = "One of the largest settlements outside of Silvermoon itself, Fairbreeze village serves as an influential center of commerce in Eversong. The nearby Sunsail Anchorage is responsible for many of the imports and exports of Quel'thalas. This bustling reputation is bolstered by the presence of Saltheril's Haven. This sprawling estate adjacent to the village hosts grand galas, uniting the disparate classes of Silvermoon in conversation and frivolity. Still, with Lightbloom Ath'Ran threatening from the south, Fairbreeze risks the same fate as Suncrown Village, devoured by the unceasing growth."
    },
    {
        name = "Windrunner Spire",
        lore = "Once home to the acclaimed Windrunner family, this grand spire has been occupied by enemies since the days of the Third War. Previously held by Scourge forces as a trophy of their victory, the tower now lies dormant, haunted by the spectres of the Windrunner family and its many tragedies."
    },
}

IMAGOdb.zones[2424].name = "Isle of Quel'Danas"
IMAGOdb.zones[2424].lore = "The Isle of Quel'Danas, the radiant crown jewel of the elven empire and home to the sacred Sunwell, has become the ultimate battleground. Xal'atath has focused the full might of her Void armada here to plunge the fount of Light and Arcane magic into eternal darkness. The skies above the island are torn by massive cosmic rifts, while Blood, High, and Void Elves unite for the first time in millennia. Shoulder to shoulder, they stand in a desperate last stand to save the absolute heart of their civilization from ruin."
IMAGOdb.zones[2424].pointsOfInterest = {
    {
        name = "The Sunwell",
        lore = "The magical center of the elves and Xal'atath's primary target. The well has been heavily fortified and pulses with volatile energies as Azeroth's most powerful magi maintain a massive shield against the all-consuming Void."
    },
    {
        name = "Sanctum of the Sun's Reach",
        lore = "Once the headquarters of the Shattered Sun Offensive, this staging ground has been rebuilt into an impenetrable fortress. Here, the united faction leaders coordinate the defense of the entire island."
    },
    {
        name = "The Dawnstar Front",
        lore = "The bloody beaches of the island where Xal'atath's invasion forces relentlessly make landfall. A brutal, unending meat grinder where arcane golems and void beasts clash in an endless war."
    },
}

IMAGOdb.zones[2393].name = "Silvermoon City"
IMAGOdb.zones[2393].lore = "Silvermoon City, the eternal crown jewel of the blood elves, has risen from the ashes to become a thriving metropolis once more. The scars of both the Scourge and the Burning Legion left little intact, but the talented artisans and magisters of the grand city have returned it to its former glory. Now, with the threat of the Voidstorm looming overhead, the sin'dorei rally their allies to push back the darkness threatening to raze the city once again."
IMAGOdb.zones[2393].pointsOfInterest = {
    {
        name = "Sunfury Spire",
        lore = "The seat of political power in Silvermoon, Lor'themar Theron and his advisors have defined the direction of Quel'thalas from within its spires. Rising stoically above the Silvermoon skyline, Sunfury Spire has stood the test of time and is a testament to the resilience of the blood elves."
    },
    {
        name = "Murder Row",
        lore = "Though some of Silvermoon's upper class would prefer to ignore it, not every street in the city is safe. In the shadowy corners of Murder Row, all manner of unsavory characters have made their home. Here, Astalor Bloodsworn experiments with anguish, a promising new source of power. An acrid scent of brimstone is carried on the breeze, suggesting the presence of dark Fel magic in its deepest corners."
    },
    {
        name = "Thalassian University",
        lore = "Silvermoon City has always been at the forefront of the arcane arts. It was the elves of Quel'thalas that first showed humanity how to wield the arcane for themselves. In that tradition, the reconstruction of Silvermoon included a sprawling university campus. Here, the next generation of mages is trained under the wise tutelage of their esteemed professors."
    },
}